var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"크윽…","JPN":"くうっ……","ENG":"Krgh...","TWN":"咳…"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"이럴 수가….","JPN":"そんな……","ENG":"I don't believe it...","TWN":"怎麼會…"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"하하, 조금은 분발할 줄 알았는데 별것도 아니었네.","JPN":"はは、もう少し手応えがあると思いましたが、大したことなかったですね。","ENG":"Haha, I thought I'd have myself a challenge, but I guess not.","TWN":"哈哈，本來以為你會振作一點的，好像也沒什麼。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L7_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"남동생분도 멋지게 나서더니, 정말 실망인걸요?","JPN":"弟さんもカッコよく登場したわりに、ガッカリですよ。","ENG":"Your brother seemed too confident, but what a let-down.","TWN":"弟弟的表現雖然很帥氣，但還是讓我很失望呢？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"엇차, 그럼 방해꾼도 사라졌으니….","JPN":"よいしょっと、それでは邪魔者もいなくなったので……","ENG":"Hup! Now that all the grunts are out of the way...","TWN":"嘿呀，既然沒了搗亂的人…"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"어라…?","JPN":"あれ……？","ENG":"Huh...?","TWN":"呃…？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_05"},{"id":"L10_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"으아앗!!","JPN":"うわあっ！！","ENG":"Aaargh!!","TWN":"呃啊啊！！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L12_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"아야야… 보안장치는 전부 해제했을 텐데?","JPN":"いたたっ……セキュリティー装置は全部解除したはずなのに。","ENG":"Oww... But I disabled all the security measures.","TWN":"哎呀呀…明明解除了所有保全裝置啊？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"어라…? 언제 수갑을 채운거죠?","JPN":"あれ……？　いつの間に手錠を？","ENG":"Huh...? When did you put cuffs on me?","TWN":"咦…？欸？什麼時候給我戴上了手銬？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"후훗, 싸울 땐, 주변 환경을 잘 살피셨어야죠!","JPN":"ふふっ、戦う時には周囲の状況をよく確認しましょうね！","ENG":"Haha, you should look around your surroundings when you fight!","TWN":"哼哼，戰鬥的時候就應該注意觀察周圍的情況！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L17_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"당신에게 빈틈을 유도하기 위한 작전이었습니다.","JPN":"これはあなたの隙を引き出すための作戦だったんです。","ENG":"This was all a ruse to make you lower your guard.","TWN":"這是為了讓你露出破綻的作戰。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"강자는 약자 앞에서 빈틈이 많아지는 법이라….","JPN":"強者は弱者の前で油断する、か……","ENG":"The strong tend to look down on the weak and let their guard down...","TWN":"強者往往會在弱者面前露出更多的破綻…"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"간단한 함정이지만, 괴도의 오만한 성격을 잘 파악하셨군요. ","JPN":"簡単な罠ですが、怪盗の傲慢な性格をよく利用しましたね。 ","ENG":"It's a simple trap, but it worked like a charm against that arrogant thief.","TWN":"雖然是一個簡單的陷阱，但卻清楚地掌握了怪盜狂妄的性格。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"나쁘지 않았습니다 탐정 씨. 이번엔 특별히 B+ 드리죠.","JPN":"悪くありませんでした、探偵さん。今回は特別にB+としましょう。","ENG":"Not bad, Detective. My evaluation of you is a B+.","TWN":"做得不錯，偵探。這次我特地給你一個B+。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"누구더러 약자라는 거에요!","JPN":"誰が弱者ですか！","ENG":"Who's the weakling now, huh?!","TWN":"你說誰是弱者！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"뭐, 어쨌든 저의 승리니까, 당신한텐 특별히 100점 만점에 60점 드릴게요.","JPN":"まあ、何はともあれ私の勝ちです。あなたには特別に100点満点中60点をあげましょう。","ENG":"Whatever the case, it's our victory. I give you 60 out of 100.","TWN":"好吧，既然是我的勝利，那100分滿分中，我就給你打個60分吧。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"아하하, 서로 그렇게나 잘 맞는데, 정말 남매 아닌 거 확실해요?","JPN":"あはは、息ピッタリ！　本当に姉弟じゃないんですか？","ENG":"Ah hah hah, you two seem to get along so well. You sure you two aren't related?","TWN":"哈哈哈，好有默契，你們倆真的不是雙胞胎嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"약자의 도발 같은 건 하나도 열받지 않습니다!","JPN":"弱者からの挑発なんて、痛くもかゆくもありません！","ENG":"A weakling's taunt doesn't bother me!","TWN":"弱者的挑釁，是不會讓我生氣的！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"흠… 그런데 여러분. 그거 아세요?","JPN":"ふむ……ところで、みなさん。知っていますか？","ENG":"Hmm... But I have something to tell you all.","TWN":"嗯…但是各位，你們知道嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"전 언제나 보험을 들어둔다는 거.","JPN":"私は、いつも保険を用意しておくんです。","ENG":"You see, I always have insurance.","TWN":"我一直都會留一手。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"흥! 이번엔 허세인가요?","JPN":"フン！　見栄を張っても無駄ですよ？","ENG":"Hmph! What kind of bluff is it this time?","TWN":"哼！你是在唬人嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"그 수갑은 혼자선 절대 풀 수 없습니다. 단념하시죠.","JPN":"その手錠は、一人では絶対に解けません。諦めなさい。","ENG":"You can never take those handcuffs off by yourself. Give up.","TWN":"你絕對無法憑一己之力摘下那個手銬，還是放棄吧。"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"응? 이건…?!","JPN":"うん？　これは……！？","ENG":"Hmm? What's this...?!","TWN":"嗯？這是…？！"},"stage":{"bg":"HALL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_WIND_03"},{"id":"L36_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"콜록! 콜록!","JPN":"ゲホ、ゲホ！","ENG":"*Cough* *Cough*","TWN":"咳咳！咳咳！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"무, 무슨 일이 일어난 거지…?","JPN":"な、何が起きたの……？","ENG":"W-what's happening...?","TWN":"發、發生了什麼事…？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"크윽! 뭔가요 이건?!","JPN":"くうっ！　何ですか、これは！？","ENG":"Kgh! What is this?!","TWN":"咳！這是什麼？！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_SPRING_NULL","text":{"KOREA":"하필이면 이 여자와 함께 묶이다니…!","JPN":"よりによって、この女と一緒に縛られるなんて……！","ENG":"Why am I tied up with her...?!","TWN":"為什麼我會和這個女人被綁在一起…！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"누군 좋은 줄 알아요?!","JPN":"私もイヤです！！","ENG":"Like I'm over the moon about it!!","TWN":"你以為我樂意嗎？！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_SPRING_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"FOOLSDSAY_JANE_THIEF_QM","text":{"KOREA":"그러게 맨날 대충 대충하니까 당하는 거야.","JPN":"ほんと、いつも詰めが甘いんだから。","ENG":"You always get stumped because you always get sloppy.","TWN":"每次都這麼馬馬虎虎，所以才會中招。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FOOLSDSAY_JANE_THIEF_QM","text":{"KOREA":"전력을 차단했을 때 빨리 훔쳐 갔으면 편했잖아.","JPN":"電力を遮断したときにさっさと盗んでしまえばよかったのに。","ENG":"It would've been easier if you just stole it when the power was out.","TWN":"如果在停電的時候動作快點，就沒這麼多麻煩了。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_JANE_THIEF_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L46_1","type":"dialog","speaker":"FOOLSDSAY_J_THIEF_NULL","text":{"KOREA":"아하하, 그럴 순 없죠. 카린 양의 얼빵한 얼굴을 보기 위해 온 거잖아요?","JPN":"あはは、それはできません。カリンさんの間抜け面を拝みにきたんですから。","ENG":"Ah hah hah, that's true. But I'm here to see Karin's goofy face.","TWN":"呼呼，那麼做可不行。我來這裡，就是為了看看卡琳小姐呆頭呆腦的樣子呀？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDSAY_J_THIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FOOLSDAY_KYLE_CONTEST_NULL","text":{"KOREA":"다, 당신은…?","JPN":"あ、あなたは……？","ENG":"Y-you're...?","TWN":"你、你是…？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_KYLE_CONTEST_NULL","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};